#pragma OPENCL EXTENSION cl_khr_fp64 : enable

typedef struct{
	double energy;
	double total_xs;
	double elastic_xs;
	double absorbtion_xs;
	double fission_xs;
	double nu_fission_xs;
} NuclideGridPoint;

typedef struct{
	int nthreads;
	long n_isotopes;
	long n_gridpoints;
	int lookups;
	int HM;
	int grid_type; 
	int hash_bins;
	int particles;
	int simulation_method;
	int binary_mode;
	int kernel_id;
	int platform_id;
